import{_ as t,o as i,c as a,a3 as n}from"./chunks/framework.LBeL10WQ.js";const h=JSON.parse('{"title":"2. Tracking & Sending","description":"","frontmatter":{"title":"2. Tracking & Sending"},"headers":[],"relativePath":"en/publishers/dedicated-email/2-tracking-sending.md","filePath":"en/publishers/dedicated-email/2-tracking-sending.md"}'),s={name:"en/publishers/dedicated-email/2-tracking-sending.md"};function o(d,e,r,l,c,g){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="step-2-tracking-validation-and-sending" tabindex="-1">Step 2: Tracking, Validation, and Sending <a class="header-anchor" href="#step-2-tracking-validation-and-sending" aria-label="Permalink to &quot;Step 2: Tracking, Validation, and Sending&quot;">​</a></h1><p>Is your mockup ready? Integrate tracking, submit a Proof, and manage the broadcast.</p><hr><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Tracking Integration</h3><p>From the <strong>&quot;Configuration&quot;</strong> tab of the campaign, retrieve the two technical elements:</p><ul><li><strong>👁️ Open Pixel</strong> — Image tag <code>&lt;img…&gt;</code> to be inserted into the email&#39;s HTML (before <code>&lt;/body&gt;</code>). Essential for counting views.</li><li><strong>🔗 Tracked links (gtinsi.de)</strong> — Replace <strong>all</strong> links to the advertiser with the provided <code>gtinsi.de</code> URLs. Essential for counting clicks.</li></ul></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Proof Validation</h3><p>To validate the technical quality, send a real test email from your router:</p><ul><li>Recipient: <code>benoit+news@getinside.fr</code></li><li>Sender: your usual sending address</li></ul><p>After verification by getinside: log in to the platform and click on <strong>&quot;Validate the campaign&quot;</strong>. Then wait for the advertiser&#39;s validation.</p></div></div><div class="danger custom-block"><p class="custom-block-title">Proof — Real email mandatory</p><p>We <strong>never</strong> validate Proofs in the form of screenshots, PDFs, or raw HTML files. The email must be received in our inbox to test responsiveness, the pixel, and redirections in real conditions.</p></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Broadcast</h3><p>Before sending, check that the brief&#39;s segmentation criteria are applied (e.g., Active 12 months, Gender, Geography).</p><p>Route the email to your base according to the defined segment.</p></div></div><div class="tip custom-block"><p class="custom-block-title">Resend to Non-openers (RGNO)</p><p>If a resend is included in the order: use <strong>exactly the same email</strong> (same HTML, same <code>gtinsi.de</code> links, same pixel). Do not modify the trackers between the initial send and the resend.</p></div><div class="gi-step"><div class="gi-step-num done">✓</div><div class="gi-step-body"><h3>Final Validation — Mandatory Action</h3><p>Once the broadcast (and potential resend) is complete, return to <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a> and click on <strong>&quot;Validate the broadcast&quot;</strong>.</p><p>Without this action, funds remain escrowed and your revenue is not triggered.</p></div></div><div class="warning custom-block"><p class="custom-block-title">Blocking Action</p><p><strong>&quot;Validate the broadcast&quot;</strong> is essential to trigger the credit of your revenue to the Wallet (available 30 days after the campaign ends).</p></div>',10)])])}const u=t(s,[["render",o]]);export{h as __pageData,u as default};
